from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Any, Dict, Optional
import json
import logging

logger = logging.getLogger(__name__)

@dataclass
class ToolResult:
    """Standardized tool result."""
    success: bool
    data: Any
    error: Optional[str] = None
    metadata: Dict = field(default_factory=dict)

    def to_string(self) -> str:
        if self.success:
            if isinstance(self.data, (dict, list)):
                return json.dumps(self.data, indent=2)
            return str(self.data)
        return f"Error: {self.error}"

class BaseTool(ABC):
    """Base class for all tools."""
    name: str
    description: str
    parameters: Dict

    @abstractmethod
    def _execute(self, **kwargs) -> ToolResult:
        pass

    def execute(self, **kwargs) -> str:
        """Execute tool with logging and error handling."""
        logger.info(f"Tool {self.name} called with: {kwargs}")
        try:
            result = self._execute(**kwargs)
            return result.to_string()
        except Exception as e:
            logger.error(f"Tool {self.name} error: {e}")
            return ToolResult(success=False, data=None, error=str(e)).to_string()

    def to_openai_format(self) -> Dict:
        return {"type": "function", "function": {"name": self.name, "description": self.description, "parameters": self.parameters}}

    def to_anthropic_format(self) -> Dict:
        return {"name": self.name, "description": self.description, "input_schema": self.parameters}

class ToolRegistry:
    def __init__(self):
        self._tools: Dict[str, BaseTool] = {}

    def register(self, tool: BaseTool):
        self._tools[tool.name] = tool

    def get(self, name: str) -> Optional[BaseTool]:
        return self._tools.get(name)

    def to_openai_format(self) -> list:
        return [t.to_openai_format() for t in self._tools.values()]

tool_registry = ToolRegistry()

import logging
import json
from datetime import datetime
from typing import Dict
import sys

class JSONFormatter(logging.Formatter):
    def format(self, record: logging.LogRecord) -> str:
        log_data = {
            "timestamp": datetime.utcnow().isoformat(),
            "level": record.levelname,
            "logger": record.name,
            "message": record.getMessage(),
        }
        if hasattr(record, "agent_id"):
            log_data["agent_id"] = record.agent_id
        if hasattr(record, "iteration"):
            log_data["iteration"] = record.iteration
        if hasattr(record, "tool_name"):
            log_data["tool_name"] = record.tool_name
        if hasattr(record, "token_usage"):
            log_data["token_usage"] = record.token_usage
        if record.exc_info:
            log_data["exception"] = self.formatException(record.exc_info)
        return json.dumps(log_data)

class AgentLogger:
    def __init__(self, agent_id: str, level: str = "INFO"):
        self.agent_id = agent_id
        self.logger = logging.getLogger(f"agent.{agent_id}")
        self.logger.setLevel(getattr(logging, level.upper()))
        if not self.logger.handlers:
            handler = logging.StreamHandler(sys.stdout)
            handler.setFormatter(JSONFormatter())
            self.logger.addHandler(handler)

    def tool_call(self, tool_name: str, arguments: Dict, result: str):
        self.logger.info(
            f"Tool call: {tool_name}",
            extra={"agent_id": self.agent_id, "tool_name": tool_name,
                   "arguments": arguments, "result_preview": result[:200]}
        )

    def llm_call(self, model: str, prompt_tokens: int, completion_tokens: int):
        self.logger.info(
            f"LLM call to {model}",
            extra={"agent_id": self.agent_id, "model": model,
                   "token_usage": {"prompt": prompt_tokens, "completion": completion_tokens,
                                   "total": prompt_tokens + completion_tokens}}
        )

from dataclasses import dataclass, field
from typing import List, Dict, Any, Callable
import json
import time
from statistics import mean

@dataclass
class TestCase:
    id: str
    task: str
    expected_output: str = None
    success_criteria: Callable[[str], bool] = None
    max_iterations: int = 20

@dataclass
class EvaluationReport:
    total_tests: int
    passed: int
    failed: int
    success_rate: float
    avg_latency: float
    avg_iterations: float
    avg_tokens: float

    def to_dict(self) -> Dict:
        return {
            "summary": {
                "total": self.total_tests,
                "passed": self.passed,
                "failed": self.failed,
                "success_rate": f"{self.success_rate:.2%}",
                "avg_latency": f"{self.avg_latency:.2f}s",
                "avg_iterations": f"{self.avg_iterations:.1f}",
                "avg_tokens": f"{self.avg_tokens:.0f}"
            }
        }

class AgentEvaluator:
    def __init__(self, agent_factory: Callable):
        self.agent_factory = agent_factory

    def evaluate(self, tests: List[TestCase]) -> EvaluationReport:
        results = []
        for test in tests:
            agent = self.agent_factory()
            start = time.time()
            try:
                result = agent.run(test.task)
                latency = time.time() - start
                if test.success_criteria:
                    success = test.success_criteria(result)
                elif test.expected_output:
                    success = test.expected_output.lower() in result.lower()
                else:
                    success = True
            except Exception as e:
                latency = time.time() - start
                success = False
                result = ""
            results.append({"success": success, "latency": latency,
                            "iterations": getattr(agent, "iteration_count", 0),
                            "tokens": getattr(agent, "total_tokens", 0)})
        passed = sum(1 for r in results if r["success"])
        return EvaluationReport(
            total_tests=len(tests), passed=passed, failed=len(tests) - passed,
            success_rate=passed / len(tests) if tests else 0,
            avg_latency=mean(r["latency"] for r in results),
            avg_iterations=mean(r["iterations"] for r in results),
            avg_tokens=mean(r["tokens"] for r in results)
        )
